import { prisma } from './client';
import { ORDER_STATUS } from '@rentalshop/constants';
import type { SimpleFilters, SimpleResponse } from './index';
import { removeVietnameseDiacritics } from '@rentalshop/utils';

// ============================================================================
// TYPES
// ============================================================================

type BusinessTypeEnum = 'GENERAL' | 'VEHICLE' | 'CLOTHING' | 'EQUIPMENT';
type PricingTypeEnum = 'FIXED' | 'HOURLY' | 'DAILY';

export interface MerchantFilters extends SimpleFilters {
  businessType?: BusinessTypeEnum;
  // subscriptionStatus removed - use subscription.status instead
  planId?: number;
  isActive?: boolean;
}

export interface MerchantCreateData {
  name: string;
  email: string;
  phone?: string;
  tenantKey?: string;
  address?: string;
  city?: string;
  state?: string;
  zipCode?: string;
  country?: string;
  businessType?: BusinessTypeEnum;
  pricingType?: PricingTypeEnum;
  taxId?: string;
  website?: string;
  description?: string;
  currency?: string; // Currency code (USD, VND), defaults to USD
  pricingConfig?: string;
  planId?: number;
  referredByMerchantId?: number; // ID of merchant who referred this merchant
  // subscriptionStatus removed - use subscription.status instead
}

export interface MerchantUpdateData extends Partial<MerchantCreateData> {
  totalRevenue?: number;
  lastActiveAt?: Date;
  isActive?: boolean;
}

// ============================================================================
// MERCHANT OPERATIONS
// ============================================================================

/**
 * Find merchant by ID
 */
export async function findById(id: number) {
  const merchant = await prisma.merchant.findUnique({
    where: { id },
    select: {
      id: true,
      name: true,
      email: true,
      phone: true,
      address: true,
      city: true,
      state: true,
      zipCode: true,
      country: true,
      website: true,
      description: true,
      businessType: true,
      pricingType: true,
      pricingConfig: true,
      taxId: true,
      currency: true,
      tenantKey: true, // Include tenantKey for public product links
      isActive: true,
      createdAt: true,
      updatedAt: true,
      subscription: {
        include: {
          plan: true
        }
      },
      outlets: {
        select: {
          id: true,
          name: true,
          isActive: true
        }
      },
      _count: {
        select: {
          outlets: true,
          users: true,
          products: true,
          customers: true
        }
      }
    }
  });

  // Get orders count separately (orders are related through outlets)
  if (merchant) {
    const ordersCount = await prisma.order.count({
      where: {
        outlet: {
          merchantId: id
        }
      }
    });

    return {
      ...merchant,
      _count: {
        ...merchant._count,
        orders: ordersCount
      }
    };
  }

  return merchant;
}

/**
 * Find merchant by email
 */
export async function findByEmail(email: string) {
  return await prisma.merchant.findUnique({
    where: { email },
    include: {
      Plan: true,
      subscription: true
    }
  });
}

/**
 * Find merchant by tenantKey
 * Used for public product pages where merchant shares link with customers
 * Supports case-insensitive search for better compatibility
 */
export async function findByTenantKey(tenantKey: string) {
  if (!tenantKey) {
    return null;
  }
  
  // Trim tenantKey but don't normalize case - let Prisma handle case-insensitive search
  const trimmedKey = tenantKey.trim();
  
  // Try exact match first (case-sensitive) - fastest lookup
  // Note: Merchant.id is Int (autoincrement), so id IS the publicId
  let merchant = await prisma.merchant.findUnique({
    where: { tenantKey: trimmedKey },
    select: {
      id: true, // This IS the publicId (Int, not CUID)
      name: true,
      description: true,
      address: true,
      phone: true,
      email: true,
      website: true,
      city: true,
      country: true,
      currency: true,
      isActive: true,
      createdAt: true,
      updatedAt: true
    }
  });
  
  // If not found with exact match, try case-insensitive search using raw SQL
  // Prisma doesn't support equals with insensitive mode directly for unique fields
  if (!merchant) {
    // Use SQL raw query for case-insensitive search
    // email, name, and currency are required fields (not null) according to schema
    // Note: Merchant.id is Int (autoincrement), so id IS the publicId
    const result = await prisma.$queryRaw<Array<{
      id: number; // This IS the publicId (Int, not CUID)
      name: string;
      description: string | null;
      address: string | null;
      phone: string | null;
      email: string;
      website: string | null;
      city: string | null;
      country: string | null;
      currency: string; // Has default "USD", so not null
      isActive: boolean;
      createdAt: Date;
      updatedAt: Date;
    }>>`
      SELECT 
        id,
        name,
        description,
        address,
        phone,
        email,
        website,
        city,
        country,
        currency,
        "isActive",
        "createdAt",
        "updatedAt"
      FROM "Merchant"
      WHERE LOWER("tenantKey") = LOWER(${trimmedKey})
      LIMIT 1
    `;
    
    if (result && result.length > 0) {
      const row = result[0];
      merchant = {
        id: row.id, // id IS the publicId (Int)
        name: row.name,
        description: row.description ?? null,
        address: row.address ?? null,
        phone: row.phone ?? null,
        email: row.email, // email is required, not null
        website: row.website ?? null,
        city: row.city ?? null,
        country: row.country ?? null,
        currency: row.currency, // currency has default "USD", so not null
        isActive: row.isActive,
        createdAt: row.createdAt,
        updatedAt: row.updatedAt
      };
    }
  }
  
  return merchant;
}

/**
 * Search merchants with filtering and pagination
 */
export async function search(filters: MerchantFilters): Promise<SimpleResponse<any>> {
  const {
    page = 1,
    limit = 20,
    search,
    businessType,
    planId,
    isActive
  } = filters;

  const skip = (page - 1) * limit;

  // Build where clause
  const where: any = {};

  if (search) {
    const searchTerm = search.trim();
    const normalizedTerm = removeVietnameseDiacritics(searchTerm);
    
    const searchConditions: any[] = [
      { name: { contains: searchTerm, mode: 'insensitive' } },
      { email: { contains: searchTerm, mode: 'insensitive' } }
    ];
    
    // Add normalized search if different from original
    if (normalizedTerm !== searchTerm) {
      searchConditions.push(
        { name: { contains: normalizedTerm, mode: 'insensitive' } }
      );
    }
    
    where.OR = searchConditions;
  }

  if (businessType) {
    where.businessType = businessType;
  }

  // subscriptionStatus filter removed - use subscription.status instead
  // if (subscriptionStatus) {
  //   where.subscription = {
  //     status: subscriptionStatus
  //   };
  // }

  if (planId !== undefined) {
    where.planId = planId;
  }

  if (isActive !== undefined) {
    where.isActive = isActive;
  }

  // Execute query
  const [merchants, total] = await Promise.all([
    prisma.merchant.findMany({
      where,
      include: {
        subscription: {
          select: {
            id: true,
            status: true,
            currentPeriodStart: true,
            currentPeriodEnd: true,
            trialStart: true,
            trialEnd: true,
            amount: true,
            currency: true,
            interval: true,
            period: true,
            discount: true,
            savings: true,
            cancelAtPeriodEnd: true,
            canceledAt: true,
            cancelReason: true,
            plan: {
              select: {
                id: true,
                name: true,
                description: true,
                basePrice: true,
                currency: true,
                trialDays: true
              }
            }
          }
        },
        _count: {
          select: {
            outlets: true,
            users: true,
            products: true,
            customers: true
          }
        }
      },
      orderBy: { createdAt: 'desc' },
      skip,
      take: limit
    }),
    prisma.merchant.count({ where })
  ]);

  return {
    data: merchants,
    total,
    page,
    limit,
    hasMore: skip + limit < total
  };
}

/**
 * Create new merchant
 */
export async function create(data: MerchantCreateData) {
  const { planId, referredByMerchantId, ...rest } = data;
  // Cast rest to any to bypass TypeScript checking for referredByMerchantId
  // This field will be properly typed after Prisma Client regeneration
  const createData: any = {
    ...(rest as any),
    ...(planId !== undefined ? { Plan: { connect: { id: planId } } } : {}),
    ...(referredByMerchantId !== undefined ? { referredByMerchantId } : {}),
    createdAt: new Date(),
    updatedAt: new Date()
  };
  return await prisma.merchant.create({
    data: createData,
    include: {
      Plan: true,
      subscription: true
    }
  });
}

/**
 * Update merchant
 */
export async function update(id: number, data: MerchantUpdateData) {
  const { planId, referredByMerchantId, ...rest } = data;
  // Cast rest to any to bypass TypeScript checking for referredByMerchantId
  // This field will be properly typed after Prisma Client regeneration
  const updateData: any = {
    ...(rest as any),
    ...(planId !== undefined ? { Plan: { connect: { id: planId } } } : {}),
    ...(referredByMerchantId !== undefined ? { referredByMerchantId } : {}),
    updatedAt: new Date()
  };
  return await prisma.merchant.update({
    where: { id },
    data: updateData,
    include: {
      Plan: true,
      subscription: true
    }
  });
}

/**
 * Delete merchant (soft delete)
 */
export async function remove(id: number) {
  return await prisma.merchant.update({
    where: { id },
    data: {
      isActive: false,
      updatedAt: new Date()
    }
  });
}

/**
 * Get merchant statistics
 */
export async function getStats(id: number) {
  const merchant = await prisma.merchant.findUnique({
    where: { id },
    include: {
        _count: {
          select: {
            outlets: true,
            users: true,
            products: true,
            customers: true
          }
        }
    }
  });

  if (!merchant) {
    return null;
  }

  // Get revenue from orders
  const revenueResult = await prisma.order.aggregate({
    where: {
      outlet: {
        merchantId: id
      },
      status: { in: [ORDER_STATUS.COMPLETED as any, ORDER_STATUS.RETURNED as any] }
    },
    _sum: {
      totalAmount: true
    }
  });

  return {
    totalOutlets: merchant._count.outlets,
    totalUsers: merchant._count.users,
    totalProducts: merchant._count.products,
    totalCustomers: merchant._count.customers,
    totalOrders: 0, // Will be calculated separately
    totalRevenue: revenueResult._sum.totalAmount || 0
  };
}

/**
 * Count merchants with optional where clause
 */
export async function count(options?: { where?: any }) {
  const where = options?.where || {};
  return await prisma.merchant.count({ where });
}

/**
 * Check for duplicate merchant by email or phone
 */
export async function checkDuplicate(email?: string, phone?: string, excludeId?: number) {
  if (!email && !phone) {
    return null;
  }

  const conditions = [];
  
  if (email) {
    conditions.push({ email });
  }
  
  if (phone) {
    conditions.push({ phone });
  }

  const where: any = {
    OR: conditions
  };

  // Exclude specific merchant ID (for update operations)
  if (excludeId) {
    where.id = { not: excludeId };
  }

  return await prisma.merchant.findFirst({ where });
}

/**
 * Get all merchants referred by a specific merchant
 * @param merchantId ID of the referring merchant
 * @param page Page number (default: 1)
 * @param limit Items per page (default: 20)
 */
export async function getReferrals(merchantId?: number, page: number = 1, limit: number = 20) {
  const skip = (page - 1) * limit;
  
  const where: any = {};
  if (merchantId) {
    where.referredByMerchantId = merchantId;
  } else {
    // Get all merchants with referrals (not null)
    where.referredByMerchantId = { not: null };
  }

  const [merchants, total] = await Promise.all([
    prisma.merchant.findMany({
      where,
      include: {
        referredBy: {
          select: {
            id: true,
            name: true,
            email: true,
            tenantKey: true
          }
        },
        subscription: {
          include: {
            plan: {
              select: {
                id: true,
                name: true,
                basePrice: true,
                currency: true
              }
            }
          }
        }
      },
      orderBy: { createdAt: 'desc' },
      skip,
      take: limit
    }),
    prisma.merchant.count({ where })
  ]);

  return {
    data: merchants,
    total,
    page,
    limit,
    hasMore: skip + limit < total
  };
}

/**
 * Get affiliate statistics - group by referrer merchant
 * Returns list of merchants who referred others, with count of referrals
 */
export async function getAffiliateStats() {
  // Get all merchants that have referred others (group by referredByMerchantId)
  const referralStats = await prisma.merchant.groupBy({
    by: ['referredByMerchantId'],
    where: {
      referredByMerchantId: { not: null }
    },
    _count: {
      id: true
    },
    orderBy: {
      _count: {
        id: 'desc'
      }
    }
  });

  // Get merchant details for each referrer
  const referrerIds = referralStats
    .map(stat => stat.referredByMerchantId)
    .filter((id): id is number => id !== null);

  const referrers = await prisma.merchant.findMany({
    where: {
      id: { in: referrerIds }
    },
    select: {
      id: true,
      name: true,
      email: true,
      tenantKey: true,
      isActive: true,
      createdAt: true
    }
  });

  // Combine stats with merchant details
  const statsWithDetails = referralStats.map(stat => {
    const referrer = referrers.find(r => r.id === stat.referredByMerchantId);
    return {
      referrer: referrer || null,
      referralCount: stat._count.id,
      referredMerchantIds: [] as number[] // Will be populated separately if needed
    };
  });

  // Get total count
  const totalReferrals = await prisma.merchant.count({
    where: {
      referredByMerchantId: { not: null }
    }
  });

  return {
    stats: statsWithDetails,
    totalReferrers: statsWithDetails.length,
    totalReferrals
  };
}

/**
 * Get list of merchants referred by a specific merchant
 */
export async function getReferredMerchants(referrerId: number) {
  const referredMerchants = await prisma.merchant.findMany({
    where: {
      referredByMerchantId: referrerId
    },
    select: {
      id: true,
      name: true,
      email: true,
      tenantKey: true,
      isActive: true,
      createdAt: true,
      subscription: {
        include: {
          plan: {
            select: {
              id: true,
              name: true
            }
          }
        }
      }
    },
    orderBy: {
      createdAt: 'desc'
    }
  });

  return referredMerchants;
}

